sys_ws_operation.operation_script:
(function process(request, response) {
     var token = request.queryParams.token;
     if (Array.isArray(token)) token = token[0];

     response.setContentType('text/html');

     if (!token) {
         return _html(response, 400, 'Token ausente', 'Link invalido (sem token).');
     }

     var mlt = new x_1880990_chain.MagicLinkToken();
     var v = mlt.verify(token);
     if (!v.valid) {
         var msg = v.reason === 'expired' ? 'Este link expirou.' :
                   v.reason === 'invalid_signature' ? 'Link invalido (assinatura nao confere).' :
                   'Link invalido (' + v.reason + ').';
         return _html(response, 401, 'Link invalido', msg);
     }

     if (v.payload.a !== 'reject') {
         return _html(response, 400, 'Acao invalida', 'Este link nao corresponde a acao de rejeitar.');
     }

     var p = new GlideRecord('x_1880990_chain_proposal');
     if (!p.get(v.payload.p)) {
         return _html(response, 404, 'Proposta nao encontrada', 'A proposta deste link nao existe mais.');
     }

     var currentState = p.state.toString();
     var newState;
     if (currentState === '20') {
         newState = 40;
         if (p.owner.toString() !== v.payload.o) {
             return _html(response, 403, 'Permissao negada', 'Voce nao e o proprietario desta proposta.');
         }
     } else if (currentState === '50') {
         newState = 70; 
         if (p.state_manager.toString() !== v.payload.o) {
             return _html(response, 403, 'Permissao negada', 'Voce nao e o gerente regional desta proposta.');
         }
     } else { 
         return _html(response, 409, 'Estado invalido',
             'A proposta nao esta em estado que permita rejeicao (estado atual: ' + currentState + ').');
     }

     p.state = newState;
     p.update();

     return _html(response, 200, 'Proposta rejeitada',
         'Proposta ' + p.number + ' rejeitada com sucesso. O comprador sera notificado. Voce pode fechar esta janela.');

     function _html(response, status, title, message) {
         response.setStatus(status);
         var color = status === 200 ? '#c0392b' : '#c0392b';
         var body =
             '<html><head><meta charset="utf-8"><title>' + title + '</title></head>' +
             '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 80px auto; text-align: center;">' +
             '<h1 style="color: ' + color + ';">' + title + '</h1>' +
             '<p style="font-size: 1.1em; color: #333;">' + message + '</p>' +
             '<p style="color: #888; font-size: 12px; margin-top: 32px;">Chain Academy &mdash; Detran SP</p>' +
             '</body></html>';
         response.getStreamWriter().writeString(body);
     }
 })(request, response);
